import{_ as e,o as t,c as o,ag as a}from"./chunks/framework.DTiDeF2Q.js";const p=JSON.parse('{"title":"Giới Thiệu Dotfiles | Dotfiles (VI)","titleTemplate":":title","description":"Khám phá tổng quan kỹ thuật về Dotfiles v0.2.495. Tương thích với macOS, Linux và WSL qua Dotfiles.","frontmatter":{"title":"Giới Thiệu Dotfiles | Dotfiles","description":"Khám phá tổng quan kỹ thuật về Dotfiles v0.2.495. Tương thích với macOS, Linux và WSL qua Dotfiles.","lang":"vi-VN","author":"Sebastien Rousseau","lastUpdated":true,"image":"/logo.png","imageAlt":"Giới Thiệu Dotfiles | Dotfiles preview","canonical":"/vi/about/","robots":"index, follow","draft":false,"noindex":false,"sitemap":true,"breadcrumbTitle":"Giới thiệu","pageType":"docs","schemaType":"WebPage","permalink":"/vi/about/"},"headers":[],"relativePath":"vi/about/index.md","filePath":"vi/about/index.md","lastUpdated":1773010926000}'),c={name:"vi/about/index.md"};function l(h,i,n,d,s,r){return t(),o("div",null,[...i[0]||(i[0]=[a('<h1 id="gioi-thieu-dotfiles" tabindex="-1">Giới Thiệu Dotfiles <a class="header-anchor" href="#gioi-thieu-dotfiles" aria-label="Permalink to &quot;Giới Thiệu Dotfiles&quot;">​</a></h1><p>Dotfiles v0.2.495 là cấu hình shell đa nền tảng được quản lý bởi Chezmoi.</p><h2 id="cai-đat" tabindex="-1">Cài Đặt <a class="header-anchor" href="#cai-đat" aria-label="Permalink to &quot;Cài Đặt&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bash</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -c</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;$(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -fsSL</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://raw.githubusercontent.com/sebastienrousseau/dotfiles/master/install.sh)&quot;</span></span></code></pre></div><h2 id="xac-minh" tabindex="-1">Xác Minh <a class="header-anchor" href="#xac-minh" aria-label="Permalink to &quot;Xác Minh&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">dot</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> doctor</span></span></code></pre></div><h2 id="cac-lenh-cot-loi" tabindex="-1">Các Lệnh Cốt Lõi <a class="header-anchor" href="#cac-lenh-cot-loi" aria-label="Permalink to &quot;Các Lệnh Cốt Lõi&quot;">​</a></h2><ul><li><code>dot apply</code> áp dụng các thay đổi cấu hình.</li><li><code>dot update</code> cập nhật repo và làm ấm cache.</li><li><code>dot doctor</code> kiểm tra đường dẫn, công cụ và tình trạng shell.</li><li><code>dot heal</code> sửa chữa trạng thái bị thiếu hoặc hỏng.</li><li><code>dot smoke-test</code> kiểm tra các chuỗi công cụ cốt lõi.</li></ul><h2 id="lien-quan" tabindex="-1">Liên Quan <a class="header-anchor" href="#lien-quan" aria-label="Permalink to &quot;Liên Quan&quot;">​</a></h2><ul><li><a href="/vi/aliases/">Bí danh</a></li><li><a href="/vi/functions/">Hàm</a></li><li><a href="/vi/paths/">Đường dẫn</a></li></ul><h2 id="lenh-chinh" tabindex="-1">Lệnh chính <a class="header-anchor" href="#lenh-chinh" aria-label="Permalink to &quot;Lệnh chính&quot;">​</a></h2><p>CLI <code>dot</code> cung cấp 53 lệnh được tổ chức theo danh mục.</p><h3 id="loi" tabindex="-1">Lõi <a class="header-anchor" href="#loi" aria-label="Permalink to &quot;Lõi&quot;">​</a></h3><ul><li><code>dot apply</code> — áp dụng các thay đổi cấu hình.</li><li><code>dot sync</code> — lấy trạng thái repo mới nhất và áp dụng.</li><li><code>dot update</code> — cập nhật repo và làm ấm bộ nhớ đệm.</li><li><code>dot add</code> — thêm tệp mới vào nguồn Chezmoi.</li><li><code>dot diff</code> — hiển thị các thay đổi đang chờ trước khi áp dụng.</li><li><code>dot status</code> — hiển thị trạng thái tệp được quản lý.</li><li><code>dot remove</code> — hủy quản lý tệp và xóa mục nguồn.</li><li><code>dot cd</code> — mở shell trong thư mục nguồn Chezmoi.</li><li><code>dot edit</code> — mở tệp được quản lý trong trình soạn thảo.</li><li><code>dot clean-cache</code> — xóa bộ nhớ đệm tạm thời.</li><li><code>dot prewarm</code> — nạp trước bộ nhớ đệm để khởi động shell nhanh hơn.</li></ul><h3 id="chan-đoan" tabindex="-1">Chẩn đoán <a class="header-anchor" href="#chan-đoan" aria-label="Permalink to &quot;Chẩn đoán&quot;">​</a></h3><ul><li><code>dot doctor</code> — xác thực đường dẫn, công cụ và trạng thái shell.</li><li><code>dot heal</code> — tự động sửa chữa trạng thái bị thiếu hoặc hỏng.</li><li><code>dot health</code> — chạy kiểm tra sức khỏe nhẹ.</li><li><code>dot verify</code> — kiểm tra tính toàn vẹn tệp so với nguồn.</li><li><code>dot scorecard</code> — in điểm chất lượng cấu hình.</li><li><code>dot snapshot</code> — ghi lại trạng thái hiện tại để so sánh sau.</li><li><code>dot smoke-test</code> — xác thực chuỗi công cụ chính từ đầu đến cuối.</li><li><code>dot chaos</code> — chèn lỗi để kiểm tra tự sửa chữa.</li><li><code>dot bundle</code> — xuất gói cấu hình di động.</li><li><code>dot rollback</code> — quay lại snapshot trước đó.</li><li><code>dot drift</code> — phát hiện thay đổi bất thường trên tệp được quản lý.</li><li><code>dot history</code> — hiển thị nhật ký lịch sử apply/sync.</li><li><code>dot benchmark</code> — đo thời gian khởi động shell.</li><li><code>dot perf</code> — phân tích khởi tạo shell chậm.</li></ul><h3 id="giao-dien" tabindex="-1">Giao diện <a class="header-anchor" href="#giao-dien" aria-label="Permalink to &quot;Giao diện&quot;">​</a></h3><ul><li><code>dot theme</code> — chuyển đổi bảng màu terminal.</li><li><code>dot wallpaper</code> — đặt hình nền desktop (macOS).</li><li><code>dot fonts</code> — cài đặt hoặc cập nhật Nerd Fonts.</li><li><code>dot tune</code> — điều chỉnh mật độ giao diện và kiểu prompt.</li></ul><h3 id="bao-mat" tabindex="-1">Bảo mật <a class="header-anchor" href="#bao-mat" aria-label="Permalink to &quot;Bảo mật&quot;">​</a></h3><ul><li><code>dot backup</code> — tạo bản sao lưu cấu hình được mã hóa.</li><li><code>dot encrypt-check</code> — xác minh mã hóa bí mật khi lưu trữ.</li><li><code>dot firewall</code> — cấu hình quy tắc tường lửa máy chủ.</li><li><code>dot telemetry</code> — kiểm soát telemetry sử dụng ẩn danh.</li><li><code>dot dns-doh</code> — bật DNS-over-HTTPS.</li><li><code>dot lock-screen</code> — khóa màn hình ngay lập tức.</li><li><code>dot usb-safety</code> — hạn chế tự động gắn USB mass-storage.</li></ul><h3 id="bi-mat" tabindex="-1">Bí mật <a class="header-anchor" href="#bi-mat" aria-label="Permalink to &quot;Bí mật&quot;">​</a></h3><ul><li><code>dot secrets-init</code> — khởi tạo backend bí mật (age / GPG).</li><li><code>dot secrets</code> — liệt kê các mục bí mật được mã hóa.</li><li><code>dot secrets-create</code> — tạo bí mật được mã hóa mới.</li><li><code>dot ssh-key</code> — tạo hoặc xoay vòng cặp khóa SSH.</li><li><code>dot ssh-cert</code> — yêu cầu chứng chỉ SSH từ CA.</li></ul><h3 id="ai" tabindex="-1">AI <a class="header-anchor" href="#ai" aria-label="Permalink to &quot;AI&quot;">​</a></h3><ul><li><code>dot ai</code> — mở phiên trợ lý AI tương tác.</li><li><code>dot ai-setup</code> — cấu hình khóa API cho nhà cung cấp AI.</li><li><code>dot ai-query</code> — gửi prompt một lần đến mô hình AI.</li><li>Wrapper công cụ AI: <code>cl</code>, <code>gemini</code>, <code>kiro</code>, <code>sgpt</code>, <code>ollama</code>, <code>opencode</code>, <code>aider</code>.</li></ul><h3 id="cong-cu" tabindex="-1">Công cụ <a class="header-anchor" href="#cong-cu" aria-label="Permalink to &quot;Công cụ&quot;">​</a></h3><ul><li><code>dot tools</code> — liệt kê công cụ CLI thay thế đi kèm và trạng thái.</li><li><code>dot new</code> — tạo tệp bí danh hoặc hàm mới.</li><li><code>dot sandbox</code> — mở shell sandbox dùng một lần.</li><li><code>dot keys</code> — hiển thị phím tắt hiện tại.</li><li><code>dot learn</code> — bắt đầu hướng dẫn tương tác.</li></ul><h3 id="thong-tin" tabindex="-1">Thông tin <a class="header-anchor" href="#thong-tin" aria-label="Permalink to &quot;Thông tin&quot;">​</a></h3><ul><li><code>dot upgrade</code> — nâng cấp Dotfiles lên bản phát hành mới nhất.</li><li><code>dot packages</code> — liệt kê các gói đã cài đặt do Dotfiles quản lý.</li><li><code>dot version</code> / <code>dot help</code> — hiển thị thông tin phiên bản hoặc cách sử dụng</li></ul>',28)])])}const m=e(c,[["render",l]]);export{p as __pageData,m as default};
